1	export type Item = {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	};
6	
7	export type QuoteStep = { op: "quote"; items: Item[] };
8	
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	
18	export type ScenarioResult = {
19	  results: QuoteResult[];
20	};
21	
22	const PROCESSING_FEE = 5;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const BLOCK_SIZE = 3;
34	const BLOCK_PRICE = 60;
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const LOYALTY_YEARS_THRESHOLD = 2;
38	const LOYALTY_DISCOUNT_RATE = 0.2;
39	const FIRST_INSURANCE_RATE = 0.1;
40	
41	const unitPrice = (type: string): number => BASE_PREMIUMS[type] ?? 0;
42	
43	const countsByType = (items: Item[]): Map<string, number> =>
44	  items.reduce(
45	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
46	    new Map<string, number>()
47	  );
48	
49	const groupTotal = (type: string, count: number): number =>
50	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
51	    ? BLOCK_PRICE
52	    : count * unitPrice(type);
53	
54	const sumBasePremiums = (items: Item[]): number => {
55	  let total = 0;
56	  for (const [type, count] of countsByType(items)) {
57	    total += groupTotal(type, count);
58	  }
59	  return total;
60	};
61	
62	const itemSurcharges = (item: Item): number => {
63	  const base = unitPrice(item.type);
64	  let surcharge = 0;
65	  if (item.cursed) surcharge += base * 0.5;
66	  if ((item.enchantment ?? 0) >= 5) surcharge += base * 0.3;
67	  return surcharge;
68	};
69	
70	const sumItemSurcharges = (items: Item[]): number =>
71	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
72	
73	const loyaltyDiscount = (
74	  basePremiums: number,
75	  customer: { yearsWithMHPCO: number }
76	): number =>
77	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
78	    ? basePremiums * LOYALTY_DISCOUNT_RATE
79	    : 0;
80	
81	const quote = (
82	  { items }: QuoteStep,
83	  customer: { yearsWithMHPCO: number }
84	): QuoteResult => {
85	  const basePremiums = sumBasePremiums(items);
86	  const raw =
87	    basePremiums +
88	    sumItemSurcharges(items) -
89	    loyaltyDiscount(basePremiums, customer) +
90	    basePremiums * FIRST_INSURANCE_RATE +
91	    PROCESSING_FEE;
92	  return { premium: Math.ceil(raw) };
93	};
94	
95	export const runScenario = (scenario: Scenario): ScenarioResult => ({
96	  results: scenario.steps.map((step) => quote(step, scenario.customer)),
97	});
